contract TeamVestingVault {
    address private _owner;

    mapping(address => uint256) private _allocation;
    mapping(address => uint256) private _releaseTime;
    mapping(address => uint256) private _withdrawn;

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockTime);
    event Withdrawal(address indexed investor, uint256 amount);

